const AWS = require('aws-sdk');
const sqs = new AWS.SQS({ apiVersion: '2012-11-05' });
const dynamodb = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  // Process each message from the SQS queue
  for (let i = 0; i < event.Records.length; i++) {
    const record = event.Records[i];
    const orderId = record.body.orderId;

    try {
      // Call external payment API to process the order
      const response = await callExternalPaymentAPI(orderId);

      if (response.status === 'success') {
        // Update DynamoDB with the processed order
        await dynamodb.update({
          TableName: 'Orders',
          Key: { orderId },
          UpdateExpression: 'SET status = :s',
          ExpressionAttributeValues: {
            ':s': 'processed'
          }
        }).promise();
      } else {
        // Log error and continue processing other orders
        console.error(`Error processing order ${orderId}: ${response.message}`);
      }
    } catch (err) {
      // Log error and continue processing other orders
      console.error(`Error processing order ${orderId}: ${err.message}`);
    }
  }
};

